const body = ($('Webhook').first().json.body) || {};
if (!body.project_id) return [{ json: { valid:false, error:'project_id obligatorio' } }];
return [{ json: { valid:true, project_id: body.project_id, version: body.version || null } }];

// FIEBDC-3 (BC3) export
// Spec ref: https://www.fiebdc.es/
const data = $input.first().json.data;
const breakdown = data.breakdown || [];

// Format date as DDMMYYYY
const d = new Date();
const pad = n => String(n).padStart(2,'0');
const fechaBC3 = pad(d.getDate()) + pad(d.getMonth()+1) + d.getFullYear();

// Sanitize text for BC3: no tildes ni saltos de linea (BC3 usa | y ~ como separadores)
const clean = s => (s || '').toString().replace(/[~|\\]/g, ' ').replace(/[\r\n]+/g, ' ').trim();
const num = n => (n === null || n === undefined || isNaN(Number(n))) ? '0.00' : Number(n).toFixed(2);

const lines = [];
// Cabecera version
lines.push(`~V|3.1|FIEBDC-3/2007|${fechaBC3}|EUROCONSTRUCTOR|ArquitAI v1.0|EUR|`);
// Concepto raiz: el proyecto entero
const rootCode = '##';
const rootName = clean(data.project_name) + ' (v' + data.version + ')';
lines.push(`~C|${rootCode}||${rootName}|${num(data.total_estimated)}|${fechaBC3}|0|`);

// Generar capitulos y partidas a partir del breakdown
// breakdown puede tener formato variable; intentamos manejar { partida, importe, unidad, cantidad, precio_unit, source } como minimo
// Si breakdown es array de objetos:
const partidas = Array.isArray(breakdown) ? breakdown : (breakdown.items || breakdown.partidas || []);

// Generar pseudo-codigos: 1, 2, 3...
let idx = 0;
const descomposicion = [];
partidas.forEach((p, i) => {
  idx++;
  const code = String(idx).padStart(3,'0');
  const unit = clean(p.unidad || p.unit || 'pa');
  const name = clean(p.partida || p.name || p.concept || ('Partida ' + idx));
  const cantidad = Number(p.cantidad || p.quantity || 1);
  const precio = Number(p.precio_unit || p.unit_price || (Number(p.importe || p.amount || 0) / Math.max(cantidad,1)));
  const importe = Number(p.importe || p.amount || (cantidad * precio));
  // Tipo 2 = partida
  lines.push(`~C|${code}|${unit}|${name}|${num(precio)}|${fechaBC3}|2|`);
  // Texto extendido si hay notes/source
  if (p.notes || p.source) {
    lines.push(`~T|${code}|${clean((p.notes || '') + (p.source ? ' [Fuente: ' + p.source + ']' : ''))}|`);
  }
  // Descomposicion: el rootCode contiene este code con cantidad
  descomposicion.push(`${code}\\${num(cantidad)}\\`);
});

if (descomposicion.length > 0) {
  lines.push(`~D|${rootCode}\\${descomposicion.join('')}|`);
}

const content = lines.join('\n') + '\n';
const filename = `${data.project_id.substring(0,8)}_v${data.version}_${fechaBC3}.bc3`;

return [{ json: {
  filename: filename,
  content: content,
  bytes: Buffer.byteLength(content, 'utf8'),
  partidas_count: partidas.length,
  total_estimated: data.total_estimated,
  project_id: data.project_id,
  cost_estimate_id: data.cost_estimate_id,
  project_name: data.project_name
}}];

